// Command claude-subagent — Phase 3 real-Claude swap of stub-subagent. Thin
// shim: load EnvelopeIn → anthropic.Run → write EnvelopeOut. Ignores the
// envelope's Dev struct (PATTERNS.md line 442 / D-F1).
package main

import (
	"context"
	"encoding/json"
	"flag"
	"fmt"
	"io"
	"os"
	"os/signal"
	"path/filepath"
	"syscall"
